text:
This code defines the kin-count simulator under ZINB, Poisson, and fixed-mean fertility assumptions. The two-parent anchor is used internally for aunts/uncles and cousins, but parents and grandparents are not reported as modeled outcomes.


Code
# The fertility distribution modeled as a zero-inflated negative binomial distribution.
simulate_relatives_zinb &lt;- function(mus, sizes, pis,
                                    n_sim = 10000,
                                    max_kids = 12) {
  draw_fert &lt;- function(n, mu, size, pi) {
    ifelse(runif(n) &lt; pi, 0L,
           as.integer(pmin(rnbinom(n, size, mu = mu), max_kids)))
  }

  draw_sibs &lt;- function(n, mu, size) {
    as.integer(pmin(rnbinom(n, size + 1, mu = mu * (size + 1) / size), max_kids - 1))
  }
  sum_fert &lt;- function(counts, gen) {
    purrr::map_int(counts, function(n) {
      if (n == 0L) 0L else as.integer(sum(draw_fert(n, mu = mus[gen], size = sizes[gen], pi = pis[gen])))
    })
  }
  sum_sibs &lt;- function(counts, gen) {
    purrr::map_int(counts, function(n) {
      if (n == 0L) 0L else as.integer(sum(draw_sibs(n, mu = mus[gen], size = sizes[gen])))
    })
  }
  # 1. Parents are a fixed pedigree anchor used to generate aunts and uncles.
  parents &lt;- rep(2L, n_sim)

  # 2. Siblings for the focal individual
  siblings &lt;- draw_sibs(n = n_sim, mu = mus[2], size = sizes[2])

  # 3. Children of the focal individual
  children &lt;- draw_fert(n = n_sim, mu = mus[1], size = sizes[1], pi = pis[1])

  # 4. Aunts & uncles (no subtraction needed)
  aunts_uncles &lt;- sum_sibs(parents, gen = 3)

  # 5. Nieces & nephews: for each sibling, simulate their fertility and sum
  nieces_nephews &lt;- sum_fert(siblings, gen = 1)

  # 6. Cousins: for each aunt/uncle, simulate their fertility and sum
  cousins &lt;- sum_fert(aunts_uncles, gen = 2)

  tibble::tibble(
    Siblings    = siblings,
    Children    = children,
    AuntUncles = aunts_uncles,
    NieceNephews = nieces_nephews,
    Cousins = cousins
  )
}

# The fertility distribution modeled as a Poisson distribution.
simulate_relatives_poisson &lt;- function(mus, 
                                       n_sim = 10000,
                                       max_kids = 12) {
  draw_fert &lt;- function(n, mu) {
    as.integer(pmin(rpois(n, lambda = mu), max_kids))
  }

  draw_sibs &lt;- function(n, mu, size) {
    as.integer(pmin(rpois(n, lambda = mu), max_kids - 1))
  }
  sum_fert &lt;- function(counts, gen) {
    purrr::map_int(counts, function(n) {
      if (n == 0L) 0L else as.integer(sum(draw_fert(n, mu = mus[gen])))
    })
  }
  sum_sibs &lt;- function(counts, gen) {
    purrr::map_int(counts, function(n) {
      if (n == 0L) 0L else as.integer(sum(draw_sibs(n, mu = mus[gen])))
    })
  }
  # 1. Parents are a fixed pedigree anchor used to generate aunts and uncles.
  parents &lt;- rep(2L, n_sim)

  # 2. Siblings for the focal individual
  siblings &lt;- draw_sibs(n = n_sim, mu = mus[2])

  # 3. Children of the focal individual
  children &lt;- draw_fert(n = n_sim, mu = mus[1])

  # 4. Aunts & uncles (no subtraction needed)
  aunts_uncles &lt;- sum_sibs(parents, gen = 3)

  # 5. Nieces & nephews: for each sibling, simulate their fertility and sum
  nieces_nephews &lt;- sum_fert(siblings, gen = 1)

  # 6. Cousins: for each aunt/uncle, simulate their fertility and sum
  cousins &lt;- sum_fert(aunts_uncles, gen = 2)

  tibble::tibble(
    Siblings    = siblings,
    Children    = children,
    AuntUncles = aunts_uncles,
    NieceNephews = nieces_nephews,
    Cousins = cousins
  )
}

# The fertility distribution fixed at the mean size.
simulate_relatives_fixed &lt;- function(ferts, sibs) {
  # 1. Parents are a fixed pedigree anchor used to generate aunts and uncles.
  parents &lt;- 2

  # 2. Siblings for the focal individual
  siblings &lt;- sibs[2]

  # 3. Children of the focal individual
  children &lt;- ferts[1]

  # 4. Aunts & uncles (no subtraction needed)
  aunts_uncles &lt;- parents * sibs[3]

  # 5. Nieces & nephews: for each sibling, simulate their fertility and sum
  nieces_nephews &lt;- siblings * ferts[1]

  # 6. Cousins: for each aunt/uncle, simulate their fertility and sum
  cousins &lt;- aunts_uncles * ferts[2]

  tibble::tibble(
    Siblings    = siblings,
    Children    = children,
    AuntUncles = aunts_uncles,
    NieceNephews = nieces_nephews,
    Cousins = cousins
  )
}

2.2 Sibling distribution for different fertility distributions
In this section, we derive the sibling distribution for the two fertility distributions discussed above: Poisson distribution and zero inflated negative binomial distribution, using the relationship established in the previous section.

2.2.1 Fertility distribution: Poisson distribution
If the fertility distribution is \(\text{Poisson}(\mu)\), then the sibling distribution is given by: for a count \(k \geq 0\), \[\begin{equation}
\begin{split}
P(N_{sib}=k) & \propto (k+1)P(N_{child}=k+1) \\
& \propto (k+1)e^{-\mu}\frac{\mu^{k+1}}{(k+1)!} \\
& = e^{-\mu}\frac{\mu^{k+1}}{k!}\propto e^{-\mu}\frac{\mu^k}{k!}, \\
\end{split}
\end{equation}
\tag{4}\] which is also a Poisson distribution with mean \(\mu\).


2.2.2 Fertility distribution: Zero inflated negative binomial distribution
If the fertility distribution is \(\text{ZINB}(\mu, \theta, \pi_0)\), then the sibling distribution is given by: for a count \(k \geq 0\), \[\begin{equation}
\begin{split}
P(N_{sib}=k) & \propto (k+1)P(N_{child}=k+1) \\
& \propto (1-\pi_0)(k+1)\binom{k+\theta}{k+1}(1-p)^{k+1} p^{\theta} \\
& \propto \frac{\theta(1-p)}{p} \frac{(k+\theta)!}{k!\theta!}(1-p)^k p^{\theta+1} \\
& \propto \binom{k+\theta}{k}(1-p)^k p^{\theta+1}, \\
\end{split}
\end{equation} \tag{5}\] where \(p = \frac{\theta}{\mu+\theta}\). Therefore, the sibling distribution is a negative binomial distribution with parameters mean fertility (\(\frac{\mu(\theta+1)}{\theta}\)), dispersion/size (\(\theta+1\)), denoted as \(\text{NB}(\frac{\mu(\theta+1)}{\theta}, \theta+1)\). The variance is \(\frac{\mu(\theta+1)}{\theta} + \frac{\mu^2(\theta+1)}{\theta^2}\).

4.1 Simulate the fertility and sibling counts


Code
simulate_fert_sib &lt;- function(model, mu, size, pi0, n_sim = 20000, max_kids = 12) {
  if (model == "Poisson") {
    # Simulate fertility counts from Poisson distribution
    fert_counts &lt;- pmin(rpois(n_sim, lambda = mu), max_kids)
  } else if (model == "ZINB") {
    # Simulate fertility counts from ZINB distribution
    fert_counts &lt;- ifelse(runif(n_sim) &lt; pi0, 0, pmin(rnbinom(n_sim, size, mu = mu), max_kids))
  }

  # Simulate sibling counts based on fertility counts
  fert_counts_tibble &lt;- tibble(fert_counts = fert_counts)
  sib_counts_tibble &lt;- fert_counts_tibble %&gt;%
    filter(fert_counts &gt; 0) %&gt;%
    tidyr::uncount(fert_counts, .remove = FALSE) %&gt;%
    mutate(sib_counts = fert_counts - 1)
  sib_counts &lt;- sib_counts_tibble$sib_counts

  list(
    model = model,
    fert_counts = fert_counts,
    sib_counts = sib_counts
  )
}

2.2 Sibling distribution for Poisson and ZINB fertility models
In this section, we derive the sibling distribution for the two fertility distributions discussed above: Poisson distribution and zero inflated negative binomial distribution, using the relationship established in the previous section.

2.2.1 Fertility distribution: Poisson distribution
If the fertility distribution is \(\text{Poisson}(\mu)\), then the sibling distribution is given by: for a count \(k \geq 0\), \[\begin{equation}
\begin{split}
P(N_{sib}=k) & = \frac{(k+1)P(N_{child}=k+1)}{\mu} \\
& = \frac{(k+1)e^{-\mu}\frac{\mu^{k+1}}{(k+1)!}}{\mu} \\
& = e^{-\mu}\frac{\mu^k}{k!}, \\
\end{split}
\end{equation}
\tag{4}\] which is also a Poisson distribution with mean \(\mu\).


2.2.2 Fertility distribution: Zero inflated negative binomial distribution
If the fertility distribution is \(\text{ZINB}(\mu, \theta, \pi_0)\), then \(E[N_{child}] = \mu(1-\pi_0)\). The sibling distribution is given by: for a count \(k \geq 0\), \[\begin{equation}
\begin{split}
P(N_{sib}=k) & = \frac{(k+1)P(N_{child}=k+1)}{\mu(1-\pi_0)} \\
& = \frac{(1-\pi_0)(k+1)\binom{k+\theta}{k+1}(1-p)^{k+1} p^{\theta}}{\mu(1-\pi_0)} \\
& = \binom{k+\theta}{k}(1-p)^k p^{\theta+1}, \\
\end{split}
\end{equation} \tag{5}\] where \(p = \frac{\theta}{\mu+\theta}\). The zero-inflation term cancels because childless women do not contribute sampled children to the next generation. Therefore, the sibling distribution is a negative binomial distribution with parameters mean \(\frac{\mu(\theta+1)}{\theta}\) and dispersion/size \(\theta+1\), denoted as \(\text{NB}(\frac{\mu(\theta+1)}{\theta}, \theta+1)\). The variance is \(\frac{\mu(\theta+1)}{\theta} + \frac{\mu^2(\theta+1)}{\theta^2}\).
